import { useState, useRef, useEffect } from "react";
import {
  MessageSquare,
  Send,
  Bot,
  User,
  Upload,
  FileText,
  Trash2,
  BookOpen,
  Loader2,
} from "lucide-react";
import { Button } from "./components/ui/button";
import { Input } from "./components/ui/input";
import { Card } from "./components/ui/card";
import { ScrollArea } from "./components/ui/scroll-area";

const API_BASE = "http://localhost:5000";

function App() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [documents, setDocuments] = useState([]);
  const [showDocs, setShowDocs] = useState(false);
  const [dragging, setDragging] = useState(false);
  const scrollRef = useRef(null);
  const fileInputRef = useRef(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, loading]);

  useEffect(() => {
    fetchDocuments();
  }, []);

  const fetchDocuments = async () => {
    try {
      const res = await fetch(`${API_BASE}/documents`);
      const data = await res.json();
      setDocuments(data.documents || []);
    } catch {
      // backend not running yet
    }
  };

  const sendMessage = async () => {
    if (!input.trim()) return;

    const userMsg = { role: "user", content: input };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setLoading(true);

    try {
      const res = await fetch(`${API_BASE}/chat`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: input }),
      });
      const data = await res.json();
      const botMsg = {
        role: "assistant",
        content: data.reply,
        sources: data.sources || [],
        context_used: data.context_used,
      };
      setMessages((prev) => [...prev, botMsg]);
    } catch {
      setMessages((prev) => [
        ...prev,
        {
          role: "assistant",
          content:
            "⚠️ Error connecting to backend. Make sure the server is running on port 5000.",
        },
      ]);
    } finally {
      setLoading(false);
    }
  };

  const uploadFiles = async (files) => {
    if (!files.length) return;
    setUploading(true);

    const formData = new FormData();
    for (const file of files) {
      formData.append("files", file);
    }

    try {
      const res = await fetch(`${API_BASE}/ingest`, {
        method: "POST",
        body: formData,
      });
      const data = await res.json();
      if (data.chunks_created) {
        setMessages((prev) => [
          ...prev,
          {
            role: "assistant",
            content: `📄 **Ingested:** ${data.files_processed} file(s) → ${data.chunks_created} chunks created.`,
            isSystem: true,
          },
        ]);
      }
      await fetchDocuments();
    } catch {
      setMessages((prev) => [
        ...prev,
        {
          role: "assistant",
          content: "⚠️ Upload failed. Is the backend running?",
          isSystem: true,
        },
      ]);
    } finally {
      setUploading(false);
    }
  };

  const clearDocuments = async () => {
    try {
      await fetch(`${API_BASE}/clear`, { method: "POST" });
      setDocuments([]);
      setMessages((prev) => [
        ...prev,
        {
          role: "assistant",
          content: "🧹 All documents cleared from the knowledge base.",
          isSystem: true,
        },
      ]);
    } catch {
      // ignore
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    setDragging(false);
    const files = Array.from(e.dataTransfer.files);
    uploadFiles(files);
  };

  const handleFileSelect = (e) => {
    uploadFiles(e.target.files);
    e.target.value = "";
  };

  return (
    <div className="flex items-center justify-center min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 p-4">
      <Card className="w-full max-w-2xl h-[85vh] flex flex-col shadow-xl border-slate-200 relative">
        {/* Header */}
        <div className="flex items-center justify-between px-5 py-4 border-b bg-white rounded-t-lg">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-primary/10 rounded-lg">
              <Bot className="w-5 h-5 text-primary" />
            </div>
            <div>
              <h1 className="font-semibold text-base">RAG Chatbot</h1>
              <p className="text-xs text-muted-foreground">
                {documents.length > 0
                  ? `${documents.length} document(s) loaded`
                  : "No documents loaded"}
              </p>
            </div>
          </div>
          <div className="flex items-center gap-1">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => fileInputRef.current?.click()}
              disabled={uploading}
              title="Upload documents"
            >
              {uploading ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                <Upload className="w-4 h-4" />
              )}
            </Button>
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setShowDocs(!showDocs)}
              title="View documents"
            >
              <BookOpen className="w-4 h-4" />
            </Button>
            <input
              ref={fileInputRef}
              type="file"
              multiple
              accept=".pdf,.txt"
              className="hidden"
              onChange={handleFileSelect}
            />
          </div>
        </div>

        {/* Document panel */}
        {showDocs && (
          <div className="border-b bg-slate-50 px-5 py-3">
            <div className="flex items-center justify-between mb-2">
              <h3 className="text-sm font-medium flex items-center gap-1">
                <FileText className="w-4 h-4" /> Documents
              </h3>
              {documents.length > 0 && (
                <Button
                  variant="ghost"
                  size="sm"
                  className="h-7 text-xs text-red-500 hover:text-red-600"
                  onClick={clearDocuments}
                >
                  <Trash2 className="w-3 h-3 mr-1" /> Clear all
                </Button>
              )}
            </div>
            {documents.length > 0 ? (
              <ul className="text-xs text-muted-foreground space-y-1">
                {documents.map((doc, i) => (
                  <li key={i} className="flex items-center gap-1.5">
                    <FileText className="w-3 h-3" /> {doc}
                  </li>
                ))}
              </ul>
            ) : (
              <p className="text-xs text-muted-foreground">
                Drop PDF/TXT files here or click the upload button.
              </p>
            )}
          </div>
        )}

        {/* Drop zone overlay */}
        {dragging && (
          <div
            className="absolute inset-0 z-10 bg-primary/10 border-2 border-dashed border-primary rounded-lg flex items-center justify-center"
            onDragOver={(e) => e.preventDefault()}
            onDragLeave={() => setDragging(false)}
            onDrop={handleDrop}
          >
            <div className="text-center">
              <Upload className="w-10 h-10 mx-auto text-primary mb-2" />
              <p className="text-sm font-medium text-primary">
                Drop files to upload
              </p>
            </div>
          </div>
        )}

        {/* Messages */}
        <ScrollArea
          className="flex-1 px-5 py-4"
          ref={scrollRef}
          onDragOver={(e) => {
            e.preventDefault();
            setDragging(true);
          }}
          onDragLeave={() => setDragging(false)}
        >
          {messages.length === 0 && (
            <div className="flex flex-col items-center justify-center h-full text-muted-foreground">
              <MessageSquare className="w-16 h-16 mb-4 opacity-20" />
              <p className="text-sm font-medium">No messages yet</p>
              <p className="text-xs mt-1">
                Upload documents, then ask a question.
              </p>
            </div>
          )}
          <div className="space-y-4">
            {messages.map((msg, i) => (
              <div
                key={i}
                className={`flex gap-3 ${
                  msg.role === "user" ? "flex-row-reverse" : ""
                }`}
              >
                {!msg.isSystem && (
                  <div
                    className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${
                      msg.role === "user"
                        ? "bg-primary text-primary-foreground"
                        : "bg-secondary text-secondary-foreground"
                    }`}
                  >
                    {msg.role === "user" ? (
                      <User className="w-4 h-4" />
                    ) : (
                      <Bot className="w-4 h-4" />
                    )}
                  </div>
                )}

                <div
                  className={`max-w-[80%] rounded-2xl px-4 py-2.5 text-sm leading-relaxed ${
                    msg.isSystem
                      ? "bg-amber-50 border border-amber-200 text-amber-800 mx-auto text-center text-xs"
                      : msg.role === "user"
                      ? "bg-primary text-primary-foreground rounded-tr-sm"
                      : "bg-secondary text-secondary-foreground rounded-tl-sm"
                  }`}
                >
                  {msg.content}
                  {msg.sources && msg.sources.length > 0 && (
                    <div className="mt-2 pt-2 border-t border-current/10">
                      <p className="text-[10px] opacity-60 font-medium">
                        Sources:
                      </p>
                      <div className="flex flex-wrap gap-1 mt-0.5">
                        {msg.sources.map((src, j) => (
                          <span
                            key={j}
                            className="inline-flex items-center gap-0.5 text-[10px] bg-current/10 px-1.5 py-0.5 rounded"
                          >
                            <FileText className="w-2.5 h-2.5" />
                            {src}
                          </span>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            ))}
            {loading && (
              <div className="flex gap-3">
                <div className="flex-shrink-0 w-8 h-8 rounded-full bg-secondary flex items-center justify-center">
                  <Bot className="w-4 h-4 text-secondary-foreground" />
                </div>
                <div className="bg-secondary text-secondary-foreground rounded-2xl rounded-tl-sm px-4 py-2.5 text-sm">
                  <span className="inline-flex gap-1">
                    <span
                      className="w-1.5 h-1.5 bg-current rounded-full animate-bounce"
                      style={{ animationDelay: "0ms" }}
                    />
                    <span
                      className="w-1.5 h-1.5 bg-current rounded-full animate-bounce"
                      style={{ animationDelay: "150ms" }}
                    />
                    <span
                      className="w-1.5 h-1.5 bg-current rounded-full animate-bounce"
                      style={{ animationDelay: "300ms" }}
                    />
                  </span>
                </div>
              </div>
            )}
          </div>
        </ScrollArea>

        {/* Input */}
        <div className="border-t bg-white rounded-b-lg px-5 py-4">
          <form
            onSubmit={(e) => {
              e.preventDefault();
              sendMessage();
            }}
            className="flex gap-2"
          >
            <Input
              placeholder={
                documents.length > 0
                  ? "Ask a question about your documents..."
                  : "Upload documents first, then ask..."
              }
              value={input}
              onChange={(e) => setInput(e.target.value)}
              disabled={loading}
              className="flex-1 bg-slate-50 border-slate-200 focus-visible:ring-primary"
            />
            <Button
              type="submit"
              disabled={loading || !input.trim()}
              size="icon"
              className="shrink-0"
            >
              <Send className="w-4 h-4" />
            </Button>
          </form>
        </div>
      </Card>
    </div>
  );
}

export default App;
